import React, { useEffect, useState } from "react";
import axios from "axios";

const statusStyles = {
  Healthy: "bg-success",
  Down: "bg-danger",
  Degraded: "bg-warning",
};

const getStatusColor = (status) => {
  switch (status) {
    case "Healthy":
      return "green";
    case "Degraded":
      return "orange";
    case "Down":
      return "red";
    default:
      return "gray";
  }
};

function App() {
  const [apis, setApis] = useState([]);
  const lastChecked =
    new Date().toLocaleString("en-GB", {
      year: "numeric",
      month: "2-digit",
      day: "2-digit",
      hour: "2-digit",
      minute: "2-digit",
      timeZone: "Europe/Paris",
      hour12: false,
    }) + " CET";

  useEffect(() => {
    const fetchStatus = async () => {
      const res = await axios.get("http://localhost:5000/api/status");
      setApis(res.data);
    };
    fetchStatus();
  }, []);

  const retryAPI = async (url) => {
    try {
      const res = await axios.get("http://localhost:5000/api/retry", {
        params: { url },
      });
      const result = res.data;

      if (result.error) {
        console.error("Retry response error:", result.error);
      }
      // Replace the old result with the new one
      setApis((prevStatuses) =>
        prevStatuses.map((api) => (api.url === url ? res.data : api))
      );
    } catch (err) {
      console.error("Retry failed for:", url, err.message);
    }
  };

  return (
    <div className="container my-5">
      <h2 className="mb-3">
        <i className="bi bi-wrench-adjustable-circle me-2"></i>
        API Connectivity Dashboard
      </h2>

      <div className="d-flex justify-content-between align-items-center mb-3">
        <div>
          <strong>Last checked:</strong> {lastChecked}
        </div>
        <button className="btn btn-outline-primary btn-sm">
          <i className="bi bi-arrow-clockwise me-1"></i> Refresh Status
        </button>
      </div>

      <table className="table table-bordered table-hover bg-white">
        <thead className="table-light">
          <tr>
            <th>API Name</th>
            <th>Status</th>
            <th>Response Time</th>
            <th>Last Error</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {apis.map((api, index) => (
            <tr key={index}>
              <td>{api.apiName}</td>
              {/* <td style={{ color: getStatusColor(api.status) }}>
                {api.status}
              </td>
              */}
              <td>
                <span
                  className={`d-inline-block rounded-circle me-2 ${
                    statusStyles[api.status]
                  }`}
                  style={{ width: "12px", height: "12px" }}
                ></span>
                {api.status}
              </td>
              <td>{api.responseTime ? `${api.responseTime} ms` : "—"}</td>
              <td>{api.lastError || "—"}</td>
              <td>
                {api.status !== "Healthy" && (
                  <button
                    onClick={() => retryAPI(api.url)}
                    class="btn btn-primary"
                  >
                    <i
                      className="bi bi-arrow-repeat me-2"
                      color="white"
                      role="button"
                      title="Retry"
                    ></i>
                  </button>
                )}
                <i
                  className="bi bi-search text-secondary"
                  role="button"
                  title="Details"
                >
                  Details
                </i>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default App;
